// ─── EXPORTAR EXCEL (CSV universal — abre direto no Excel) ───────────────────
const exportarExcel = (nomeArquivo, colunas, linhas) => {
  const BOM = "\uFEFF"; // garante acentos corretos no Excel
  const cabecalho = colunas.join(";");
  const corpo = linhas.map(linha =>
    colunas.map(col => {
      const v = linha[col] ?? "";
      const s = String(v).replace(/"/g, '""');
      return s.includes(";") || s.includes("\n") ? `"${s}"` : s;
    }).join(";")
  ).join("\n");
  const csv = BOM + cabecalho + "\n" + corpo;
  const blob = new Blob([csv], { type: "text/csv;charset=utf-8;" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url; a.download = nomeArquivo + ".csv"; a.click();
  URL.revokeObjectURL(url);
};


